void solve(int CASE)
{
	int n, m; cin >> n >> m;

	var lim = vector<int>(n + 1, n);       // 位置 i 值的最大限制
	var mus = vector<int>(n + 1, 2e6 + 1); // 位置 i 可能必须放的值
	var s_lim = vector<int>(n + 2);
	var s_mus = vector<int>(n + 2);
	fa(i, 1, n + 1)s_lim[i] = s_mus[i] = i;

	var modifyRange = [](
		vector<int>& p, vector<int>& s,
		int l, int r, int val)->void {
			// 从小到大贪心，每个点只需要赋值一次，也就是最小的那一次
			// 故不使用线段树，使用链式并查集
			var find = [&](var find, int x)->int {
				if (s[x] == x)return s[x];
				return s[x] = find(find, s[x]);
				};
			for (int i = find(find, l); i <= r; i = find(find, i + 1)) {
				p[i] = val;
				s[i] = find(find, i + 1);
			}
		};

	var has = vector<bool>(n + 1); // i 是否作为必须放的值
	var p = vector<pair<int, pii>>();
	fa(i, 1, m) {
		int l, r, k; cin >> l >> r >> k;
		p.pb({ k, {l,r} });
		has[k] = 1;
	}
	sort(all(p)); // 按限制排序，贪心

	pair<int, pii> last = { -1, {} };
	for (const var& [k, v] : p) {
		const var& [l, r] = v;
		var[nl, nr] = last.py;

		modifyRange(lim, s_lim, l, r, k);
		if (last.px == k) {
			// 两段限制一致，求交集，交集内必须放最大限制的值
			if (nr < l) {
				cout << 0 << endl;
				return;
			}
			nl = l;
			nr = min(nr, r);
		}
		else {
			// 两段限制不一致，更新交集
			if (last.px != -1)
				modifyRange(mus, s_mus, nl, nr, last.px);
			nl = l, nr = r;
		}
		last = { k, { nl, nr } };
	}
	if (last.px != -1) {
		var[nl, nr] = last.py;
		modifyRange(mus, s_mus, nl, nr, last.px);
	}

	var cnt = vector<int>(n + 1);  // i 作为区间的最大值限制，出现了几次
	var jiao = vector<int>(n + 1); // i 作为区间内必须出现的数，出现了几次 
	fa(i, 1, n) {
		cnt[lim[i]]++;
		if (mus[i] <= n and mus[i] <= lim[i])
			jiao[mus[i]]++;
	}

	ll ans = 1;
	int free = 0; // 限制解除的位置个数（即已把限制数妥善安置）
	fb(i, n, 1) {
		free += cnt[i];
		if (has[i])ans = ans * jiao[i] % mod;
		else ans = ans * free % mod;
		free--;

		if (free < 0) {
			cout << 0 << endl;
			return;
		}
	}
	cout << ans << endl;
	return;
}
